import DataService from '../../services/DataService';
let buttons = [{
    title: 'BacktoList',
    iconClass: 'fa fa-angle-double-left',
    callbackfunction: 'BacktoList',
    additionalClass: '',
    isdisabled: false,
    isvisible: true,
    checkPrivilege: false,
    id: '',
},
];
let leftsearchSchema = [
    {
        fieldName: 'ClientName',
        fieldType: "searchableselect",
        fieldIcon: "fa-user",
        paramName: "ClientIds",
        fieldSearchConditionName: ['RATE_SCH.client_id'],
        isSearch: false,
        value: "",
        actionButtons: { selectAll: true, active: true, inactive: true, clear: true },
        itemFields: ['text'],
        groupFields: ['groupText'],
        isMultiple: false,
        maxRenderItems: 50,
        placeholder: "",
        statusFieldConfig: {
            fieldName: 'status',
            activeValues: ['Active', 'active'],
            inactiveValues: ['Inactive', 'inactive'],
            activeColor: '#28a745',
            inactiveColor: '#dc3545'
        },
        minSearchLength: 0,
        listOptions: [],
        onChange: null
    },
    {
        fieldName: 'WORKCODE',
        fieldType: "ddl-check",
        fieldIcon: "fa fa-circle-o-notch",
        fieldSearchConditionName: ['CODE.WORK_CODE_ID'],
        isSearch: false,
        value: "",
        listOptions: []
    },
];
let listActions = [{
    title: 'Edit',
    callbackfunction: 'Edit',
    href: 'javascript:void(0)',
    icon: 'fa fa-pencil text-success action-icon',
    additionalSpan: '',
    isvisible: true,
    isdisabled: false,
}
];

function bindleftCommonSearchdropdown(instance, fieldName) {
    var vm = instance;    
    if (fieldName == 'WORKCODE') {
        DataService.GetWorkCodes().then((response) => {
            if (response.data.result.length > 0) {
                vm.leftSearchFields[1].listOptions = [];
                response.data.result.forEach(element => {
                    let Obj = {
                        value: `${element.Value}`,
                        name: element.Text
                    }
                    vm.leftSearchFields[1].listOptions.push(Obj);
                });
            }
        });
    }    
}
export default { buttons, leftsearchSchema, listActions, bindleftCommonSearchdropdown }; 